940	  \label{thm:Scheme_cechCohomology_subsingleton_of_cechCochain_exactAt}
941	  \lean{AlgebraicGeometry.Scheme.cechCohomology_subsingleton_of_cechCochain_exactAt}
942	  Let $\mathcal F$ be a sheaf of $k$-modules on a $k$-scheme $X$, let $\mathfrak U = \{\mathcal U_i\}$ be an open cover, and let $n \ge 1$. If the Čech cochain complex of $\mathcal F$ with respect to $\mathfrak U$ is exact at degree $n$, then the Čech cohomology group $\check H^n(\mathfrak U, \mathcal F)$ is a subsingleton.
943	\end{theorem}
944	
945	\begin{proof}
946	  Exactness at degree $n$ means that the $n$-cocycles equal the $n$-coboundaries, so the quotient $\check H^n$ has at most one element.
947	\end{proof}
948	
949	\begin{theorem}[Čech acyclicity for the structure sheaf]
950	  \label{thm:basicOpenCover_isCechAcyclicCover_toModuleKSheaf}
951	  \lean{AlgebraicGeometry.Scheme.basicOpenCover_isCechAcyclicCover_toModuleKSheaf}
952	  \uses{def:Scheme_basicOpenCover, def:Scheme_IsCechAcyclicCover, thm:Scheme_basicOpenCover_finset_inf_eq_basicOpen_prod, thm:Scheme_basicOpenCover_finset_inf_le, thm:Scheme_basicOpenCover_finset_inf_isLocalization, thm:Scheme_cechCohomology_subsingleton_of_cechCochain_exactAt, def:Scheme_splitEpi_pi_lift_of_injective}
953	  The Čech cohomology $\check H^n(\mathfrak U, \mathcal O_X)$ vanishes for every $n \ge 1$.
954	\end{theorem}
955	
956	\begin{proof}
957	  \uses{thm:Scheme_basicOpenCover_finset_inf_isLocalization, def:Scheme_IsCechAcyclicCover, thm:Scheme_cechCohomology_subsingleton_of_cechCochain_exactAt, def:Scheme_splitEpi_pi_lift_of_injective}
958	  The classical proof proceeds in four steps.
959	
960	  \textbf{Step~1: Reduction to per-generator local exactness.} Since $s$ generates the unit ideal, exactness of a map of $\mathcal O_X(U)$-modules is a local property at the cover $\{D(f)\}_{f \in s}$. It suffices to prove exactness after localizing at each generator $f \in s$.
961	
962	  \textbf{Step~2: Identification of the localized complex.} Localizing at $f$ identifies the factor at $(f_0,\dots,f_n)$ with $\mathcal O_X(U)[1/(f f_0 \cdots f_n)]$. Reassembling, the localized Čech complex is naturally isomorphic to the Čech complex of $D(f)$ with respect to the restricted cover $\{D(f) \cap D(f')\}_{f' \in s}$.
963	
964	  \textbf{Step~3: Contraction by extra degeneracy.} In the cover of $D(f)$, the member indexed by $f' = f$ is $D(f)$ itself. The augmented Čech complex therefore admits a section: map a family to its component at $f$. This section extends to an extra degeneracy on the augmented simplicial object, exhibiting the augmented Čech complex as contractible. Consequently the complex is exact in all positive degrees.
965	
966	  \textbf{Step~4: Globalization.} Each localized differential is exact, so the unlocalized differential is exact by the local-to-global principle for spanning sets. Hence $\check H^n(\mathfrak U, \mathcal O_X) = 0$ for $n \ge 1$.
967	\end{proof}
968	
969	\begin{remark}[Finite-subspanning reduction]
970	  \label{rem:basic_open_cech_finite_subspanning}
971	  Although $s$ need not be finite, the unit ideal condition guarantees a finite subset $s_0 \subseteq s$ already generating the unit ideal. The two covers indexed by $s$ and $s_0$ induce the same sieve on $U$, so the refinement map is a quasi-isomorphism. It therefore suffices to prove acyclicity for a finite cover, which makes every cochain factor a finite product.
972	\end{remark}
973	
974	\begin{remark}[Lean implementation]
975	  The proof uses the local-to-global exactness theorem for spanning sets, the structure-sheaf-section-as-localization theorem for affine basic opens, exactness preservation under localization, and the extra-degeneracy contraction theorem for augmented simplicial objects. Mathlib does not currently host a formalisation of the Koszul complex or of the Čech-to-derived-functor spectral sequence; the proof above bypasses both by working directly with the augmented complex on each basic-open patch.
976	\end{remark}
977	
978	\subsection{Use in the project}
979	
980	The chain built in this chapter composes as follows. Čech acyclicity for the structure sheaf on basic-open covers yields the Čech-acyclic hypothesis. The comparison isomorphism between Čech and derived cohomology (a project-local construction, queued for a subsequent iteration) yields the $\HasCechToHModuleIso$ hypothesis. The existence producer of Theorem~\ref{thm:Scheme_hasAffineCechAcyclicCover_of_basicOpen} then assembles these into $\HasAffineCechAcyclicCover$, which the producer of Theorem~\ref{thm:Scheme_instIsAffineHModuleVanishing_of_hasAffineCechAcyclicCover} converts into $\IsAffineHModuleVanishing$. Together with the $H^0$ finiteness ladder of Chapter~\ref{chap:Cohomology_StructureSheafModuleK}, this closes Phase~A step~6 and delivers the genus carrier $\Module.\Finite\,k\,H^1(C, \mathcal O_C)$.
